// Extract data from webhook body
const data = $json.body || $json;

// Build content string from available fields
const parts = [];
if (data.name) parts.push('Name: ' + data.name);
if (data.email) parts.push('Email: ' + data.email);
if (data.company) parts.push('Company: ' + data.company);
if (data.title) parts.push('Title: ' + data.title);
if (data.phone) parts.push('Phone: ' + data.phone);
if (data.notes) parts.push('Notes: ' + data.notes);
if (data.message) parts.push('Message: ' + data.message);

const content = parts.join('\n') || JSON.stringify(data);

return [{
  json: {
    content: content,
    speaker: data.source || 'webhook',
    enhanced: true,
    tags: ['webhook', 'real-time', data.source || 'unknown'].filter(Boolean),
    email: data.email || undefined,
    website_url: data.website || data.website_url || undefined
  }
}];

const result = $input.first().json;
return [{
  json: {
    success: result.success || false,
    message: result.success ? 'Memorized successfully' : 'Failed to memorize',
    data: result.data || null
  }
}];
